def get_feishu_token():
    """获取飞书访问令牌"""
    url = "https://open.feishu.cn/open-apis/auth/v3/tenant_access_token/internal"
    payload = {"app_id": FEISHU_APP_ID, "app_secret": FEISHU_APP_SECRET}
    try:
        data = json.dumps(payload).encode('utf-8')
        req = urllib.request.Request(url, data=data, headers={'Content-Type': 'application/json'})
        with urllib.request.urlopen(req, timeout=10) as response:
            result = json.loads(response.read().decode('utf-8'))
            if result.get('code') == 0:
                return result.get('tenant_access_token')
            return None
    except Exception as e:
        return None

def send_feishu(title: str, content: str, image_path: str) -> bool:
    """发送飞书群消息（图文）"""
    token = get_feishu_token()
    if not token:
        print("❌ 获取飞书令牌失败")
        return False

    # 上传图片
    try:
        import base64
        with open(image_path, 'rb') as f:
            img_data = base64.b64encode(f.read()).decode('utf-8')
    except Exception as e:
        print(f"❌ 读取图片失败：{e}")
        return False

    # 先上传媒体文件
    upload_url = "https://open.feishu.cn/open-apis/im/v1/images"
    upload_headers = {
        'Authorization': f'Bearer {token}',
        'Content-Type': 'application/json'
    }
    upload_payload = {
        "image_type": "message",
        "image": img_data
    }

    image_key = None
    try:
        data = json.dumps(upload_payload).encode('utf-8')
        req = urllib.request.Request(upload_url, data=data, headers=upload_headers)
        with urllib.request.urlopen(req, timeout=10) as response:
            result = json.loads(response.read().decode('utf-8'))
            if result.get('code') == 0:
                image_key = result.get('data', {}).get('image_key')
    except Exception as e:
        print(f"❌ 上传图片失败：{e}")

    # 发送消息
    url = "https://open.feishu.cn/open-apis/im/v1/messages?receive_id_type=chat_id"
    headers = {
        'Authorization': f'Bearer {token}',
        'Content-Type': 'application/json'
    }

    # 构建图文消息
    if image_key:
        msg_content = {
            "config": {"wide_screen_mode": True},
            "header": {
                "template": "blue",
                "title": {"content": title, "tag": "plain_text"}
            },
            "elements": [
                {"tag": "img", "image_key": image_key},
                {"tag": "hr"},
                {"tag": "markdown", "content": content},
                {"tag": "note", "elements": [{"tag": "plain_text", "content": "🤖 AI 产业早报 · 每日更新"}]}
            ]
        }
    else:
        msg_content = {
            "config": {"wide_screen_mode": True},
            "header": {
                "template": "blue",
                "title": {"content": title, "tag": "plain_text"}
            },
            "elements": [
                {"tag": "markdown", "content": content},
                {"tag": "note", "elements": [{"tag": "plain_text", "content": "🤖 AI 产业早报 · 每日更新"}]}
            ]
        }

    payload = {
        "receive_id": FEISHU_GROUP_CHAT_ID,
        "msg_type": "interactive",
        "content": json.dumps(msg_content)
    }

    try:
        data = json.dumps(payload).encode('utf-8')
        req = urllib.request.Request(url, data=data, headers=headers)
        with urllib.request.urlopen(req, timeout=10) as resp:
            result = json.loads(resp.read().decode('utf-8'))
            if result.get('code') == 0:
                print("✅ 飞书推送成功")
                return True
            else:
                print(f"❌ 飞书推送失败：{result}")
                return False
    except Exception as e:
        print(f"❌ 飞书推送异常：{e}")
        return False"}

